from pptx import Presentation
from pptx.oxml.ns import qn

prs = Presentation('outputs/deck_normalized.pptx')
print(f'Total slides in output: {len(prs.slides)}')
print()
print('Verifying titles (should all be Arial Bold 36pt):')
for i, slide in enumerate(prs.slides):
    for shape in slide.shapes:
        if shape.has_text_frame and shape.top < 1_500_000 and shape.text_frame.text.strip():
            para = shape.text_frame.paragraphs[0]
            defRPr = para._p.find('.//' + qn('a:defRPr'))
            if defRPr is not None:
                latin = defRPr.find(qn('a:latin'))
                typeface = latin.get('typeface') if latin is not None else 'N/A'
                bold = defRPr.get('b')
                sz = defRPr.get('sz')
                print(f'  Slide {i+1}: font={typeface}, bold={bold}, sz={sz} ({int(sz)//100}pt), title={repr(shape.text_frame.text[:25])}')

print()
print('Verifying slide order (slide 7 Key Features should now be slide 2):')
for i, slide in enumerate(prs.slides):
    for shape in slide.shapes:
        if shape.has_text_frame and shape.top < 1_500_000 and shape.text_frame.text.strip():
            print(f'  Slide {i+1}: {repr(shape.text_frame.text[:30])}')
            break

print()
print('Verifying footers:')
for i, slide in enumerate(prs.slides):
    for shape in slide.shapes:
        if shape.has_text_frame and 'Confidential' in shape.text_frame.text:
            print(f'  Slide {i+1}: {repr(shape.text_frame.text)}')
" 2>&1

